import { NextRequest, NextResponse } from 'next/server'
import { auth } from '@clerk/nextjs/server'
import { supabase } from '@/lib/supabase'

interface Review {
  id: string
  user_id: string
  platform: string
  rating: number
  content: string | null
  author_name: string | null
  status: 'pending' | 'approved' | 'rejected' | null
  sentiment_label: 'positive' | 'negative' | 'neutral' | null
  created_at: string
}

interface Reply {
  id: string
  review_id: string
  ai_generated: boolean | null
  is_edited_by_human: boolean | null
}

export async function GET(req: NextRequest) {
  try {
    const { userId } = await auth()

    if (!userId) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    const { searchParams } = new URL(req.url)
    const days = parseInt(searchParams.get('days') || '30')
    const startDate = new Date()
    startDate.setDate(startDate.getDate() - days)

    const { data: reviews, error: reviewsError } = await supabase
      .from('reviews')
      .select('*')
      .eq('user_id', userId)
      .gte('created_at', startDate.toISOString())
      .order('created_at', { ascending: false })

    if (reviewsError) {
      console.error('Analytics reviews error:', reviewsError)
      return NextResponse.json(
        { error: 'Failed to fetch reviews: ' + reviewsError.message },
        { status: 500 }
      )
    }

    const { data: allReviews, error: allReviewsError } = await supabase
      .from('reviews')
      .select('*')
      .eq('user_id', userId)

    if (allReviewsError) {
      console.error('All reviews error:', allReviewsError)
    }

    const reviewIds = allReviews?.map((r) => r.id) || []
    const { data: replies, error: repliesError } = reviewIds.length > 0
      ? await supabase.from('replies').select('*').in('review_id', reviewIds)
      : { data: null, error: null }

    if (repliesError) {
      console.error('Analytics replies error:', repliesError)
    }

    const totalReviews = allReviews?.length || 0
    const pendingReviews = allReviews?.filter((r) => r.status === 'pending').length || 0
    const repliedReviews = allReviews?.filter((r) => r.status === 'approved').length || 0
    const rejectedReviews = allReviews?.filter((r) => r.status === 'rejected').length || 0

    const avgRating = totalReviews > 0
      ? (allReviews?.reduce((acc, r) => acc + (r.rating || 0), 0) || 0) / totalReviews
      : 0

    const sentimentDistribution = {
      positive: allReviews?.filter((r) => r.sentiment_label === 'positive').length || 0,
      negative: allReviews?.filter((r) => r.sentiment_label === 'negative').length || 0,
      neutral: allReviews?.filter((r) => r.sentiment_label === 'neutral').length || 0,
    }

    const platformDistribution: Record<string, number> = {}
    allReviews?.forEach((r) => {
      const platform = r.platform || 'unknown'
      platformDistribution[platform] = (platformDistribution[platform] || 0) + 1
    })

    const ratingDistribution = [0, 0, 0, 0, 0]
    allReviews?.forEach((r) => {
      const rating = Math.min(Math.max(Math.floor(r.rating || 0), 1), 5)
      ratingDistribution[rating - 1]++
    })

    const timeSeriesData: Record<string, { date: string; count: number; totalRating: number }> = {}
    for (let i = 0; i < days; i++) {
      const d = new Date()
      d.setDate(d.getDate() - i)
      const dateKey = d.toISOString().split('T')[0]
      timeSeriesData[dateKey] = { date: dateKey, count: 0, totalRating: 0 }
    }

    reviews?.forEach((r) => {
      const dateKey = r.created_at?.split('T')[0]
      if (dateKey && timeSeriesData[dateKey]) {
        timeSeriesData[dateKey].count++
        timeSeriesData[dateKey].totalRating += r.rating || 0
      }
    })

    const totalReplies = replies?.length || 0
    const aiGeneratedReplies = replies?.filter((r) => r.ai_generated).length || 0
    const editedReplies = replies?.filter((r) => r.is_edited_by_human).length || 0
    const responseRate = totalReviews > 0 ? (repliedReviews / totalReviews) * 100 : 0
    const recentReviews = allReviews?.slice(0, 10) || []

    return NextResponse.json({
      stats: {
        totalReviews,
        pendingReviews,
        repliedReviews,
        rejectedReviews,
        avgRating: parseFloat(avgRating.toFixed(1)),
        responseRate: parseFloat(responseRate.toFixed(1)),
        totalReplies,
        aiGeneratedReplies,
        editedReplies,
      },
      sentimentDistribution,
      platformDistribution,
      ratingDistribution,
      timeSeriesData: Object.values(timeSeriesData).reverse(),
      recentReviews,
    })
  } catch (error: unknown) {
    console.error('Analytics API error:', error)
    const message = error instanceof Error ? error.message : 'Unknown error'
    return NextResponse.json({ error: message }, { status: 500 })
  }
}

import { NextRequest, NextResponse } from 'next/server';
import {
  autoReplyScheduler,
  getScheduledReplies,
  getAutoReplyRules,
  updateAutoReplyRule,
  cancelScheduledReply,
  scheduleReply,
  initializeUserAutoReply
} from '@/lib/auto-reply/scheduler';
import { auth } from '@clerk/nextjs/server';

/**
 * POST /api/auto-reply
 * Schedule a new auto-reply or trigger immediate processing
 */
export async function POST(request: NextRequest) {
  try {
    // Get current user using Clerk auth
    const { userId } = await auth();

    if (!userId) {
      return NextResponse.json(
        { error: 'Authentication required' },
        { status: 401 }
      );
    }

    const body = await request.json();
    const { action } = body;

    switch (action) {
      case 'schedule':
        const { reviewId, platform, replyText, delayMinutes, autoPost } = body;
        const scheduled = await scheduleReply(userId, reviewId, platform, replyText, delayMinutes, autoPost);
        if (!scheduled) {
          return NextResponse.json({ error: 'Failed to schedule reply' }, { status: 500 });
        }
        return NextResponse.json({ success: true, scheduled });

      case 'cancel':
        const { scheduledId } = body;
        const cancelled = await cancelScheduledReply(scheduledId);
        return NextResponse.json({ success: cancelled, message: cancelled ? 'Reply cancelled' : 'Could not cancel reply' });

      case 'execute_now':
        // Execute a scheduled reply immediately
        const { replyId } = body;
        // Implementation would call executeReply
        return NextResponse.json({ success: true, message: 'Reply executed' });

      default:
        return NextResponse.json({ error: 'Unknown action' }, { status: 400 });
    }

  } catch (error: unknown) {
    console.error('[Auto Reply API Error]:', error);
    const message = error instanceof Error ? error.message : 'Unknown error';
    return NextResponse.json({ error: message }, { status: 500 });
  }
}

