          .eq('id', existingReply.id)
          .select()
          .single()
      } else {
        // Insert new reply
        result = await (supabase
          .from('replies')
          .insert({
            review_id: reviewId,
            reply_text: replyText,
            ai_generated: aiGenerated,
            is_edited_by_human: !aiGenerated,
          }) )
          .select()
          .single()
