                            </>
                          ) : (
                            <>
                              <Wrench className="w-5 h-5" />
                              Request Setup ($8)
                            </>
                          )}
                        </button>
                      </form>
                    </div>
                  </div>

                  {/* Right: Info & Testimonials */}
                  <div className="space-y-6">
                    {/* How It Works */}
