                            <p className="text-white font-medium text-xs">{testimonial.name}</p>
                            <p className="text-white/50 text-xs">{testimonial.business}</p>
                          </div>
                        ))}
                      </div>
                    </div>
                  </div>
                </div>
              </motion.div>
