'use client'

import { useState, useEffect, useCallback } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { 
  MapPin, 
  Bell, 
  BellRing,
  BellOff,
  Navigation,
  CheckCircle,
  XCircle,
  Settings,
  Shield,
  Info
} from 'lucide-react'

interface PermissionState {
  location: 'granted' | 'denied' | 'prompt' | 'checking'
  notification: 'granted' | 'denied' | 'prompt' | 'checking'
}

interface UserLocation {
  latitude: number
  longitude: number
  city?: string
  country?: string
  address?: string
}

export default function PermissionManager() {
  const [permissions, setPermissions] = useState<PermissionState>({
    location: 'checking',
    notification: 'checking'
  })
  const [userLocation, setUserLocation] = useState<UserLocation | null>(null)
  const [showLocationModal, setShowLocationModal] = useState(false)
  const [showNotificationModal, setShowNotificationModal] = useState(false)
  const [isRequesting, setIsRequesting] = useState(false)

  // Check current permission status on mount
  useEffect(() => {
    checkPermissions()
    loadSavedLocation()
  }, [])

  const checkPermissions = async () => {
    // Check location permission
    if (typeof navigator !== 'undefined' && 'geolocation' in navigator) {
      try {
        // Try to get permission state
        if ('permissions' in navigator) {
          const locationPerm = await (navigator as any).permissions.query({ name: 'geolocation' })
          setPermissions(prev => ({ 
            ...prev, 
            location: locationPerm.state as 'granted' | 'denied' | 'prompt'
          }))
          
          locationPerm.addEventListener('change', () => {
            setPermissions(prev => ({ 
              ...prev, 
              location: locationPerm.state as 'granted' | 'denied' | 'prompt'
            }))
          })
        } else {
          // Fallback for browsers without permissions API
          (navigator as any).geolocation.getCurrentPosition(
            () => setPermissions(prev => ({ ...prev, location: 'granted' })),
            () => setPermissions(prev => ({ ...prev, location: 'prompt' })),
            { timeout: 5000 }
          )
        }
      } catch (error) {
        console.error('Error checking location permission:', error)
        setPermissions(prev => ({ ...prev, location: 'prompt' }))
      }
    } else {
      setPermissions(prev => ({ ...prev, location: 'denied' }))
    }

    // Check notification permission
    if (typeof window !== 'undefined' && 'Notification' in window) {
      setPermissions(prev => ({ 
        ...prev, 
        notification: Notification.permission as 'granted' | 'denied' | 'prompt'
      }))
    } else {
      setPermissions(prev => ({ ...prev, notification: 'denied' }))
    }
  }

  const loadSavedLocation = () => {
    const saved = localStorage.getItem('user-location')
    if (saved) {
      try {
        setUserLocation(JSON.parse(saved))
      } catch (e) {
        console.error('Error loading saved location:', e)
      }
    }
  }

  const requestLocation = async (): Promise<boolean> => {
    setIsRequesting(true)
    
    return new Promise((resolve) => {
      if (typeof navigator === 'undefined' || !('geolocation' in navigator)) {
        setPermissions(prev => ({ ...prev, location: 'denied' }))
        setIsRequesting(false)
        resolve(false)
        return
      }

      navigator.geolocation.getCurrentPosition(
        async (position) => {
          const { latitude, longitude } = position.coords
          
          // Try to get address from coordinates (reverse geocoding)
          let locationData: UserLocation = { latitude, longitude }
          
          try {
            // Using OpenStreetMap Nominatim for free geocoding
            const response = await fetch(
              `https://nominatim.openstreetmap.org/reverse?format=json&lat=${latitude}&lon=${longitude}&zoom=18&addressdetails=1`,
              { headers: { 'Accept-Language': 'en-US,en' } }
            )
            
            if (response.ok) {
              const data = await response.json()
              locationData = {
                latitude,
                longitude,
                city: data.address?.city || data.address?.town || data.address?.village,
                country: data.address?.country,
                address: data.display_name
              }
            }
          } catch (error) {
            console.error('Error getting address:', error)
          }
          
          // Save location
          localStorage.setItem('user-location', JSON.stringify(locationData))
          setUserLocation(locationData)
          setPermissions(prev => ({ ...prev, location: 'granted' }))
          setIsRequesting(false)
          resolve(true)
        },
        (error) => {
          console.error('Location error:', error)
          setPermissions(prev => ({ ...prev, location: 'denied' }))
          setIsRequesting(false)
          resolve(false)
        },
        {
          enableHighAccuracy: true,
          timeout: 10000,
          maximumAge: 0
        }
      )
    })
  }

  const requestNotificationPermission = async (): Promise<boolean> => {
    setIsRequesting(true)
    
    try {
      if (!('Notification' in window)) {
        setPermissions(prev => ({ ...prev, notification: 'denied' }))
        setIsRequesting(false)
        return false
      }

      const permission = await Notification.requestPermission()
      setPermissions(prev => ({ ...prev, notification: permission as 'granted' | 'denied' | 'prompt' }))
      
      if (permission === 'granted') {
        // Show a welcome notification
        showNotification(
          '🎉 Notifications Enabled!',
          'You\'ll now receive updates about new reviews and AI responses.',
          '/icon.png'
        )
        
        // Register service worker for background notifications
        await registerServiceWorker()
      }
      
      setIsRequesting(false)
      return permission === 'granted'
    } catch (error) {
      console.error('Notification error:', error)
      setPermissions(prev => ({ ...prev, notification: 'denied' }))
      setIsRequesting(false)
      return false
    }
  }

  const registerServiceWorker = async () => {
    if (typeof navigator !== 'undefined' && 'serviceWorker' in navigator) {
      try {
        const registration = await navigator.serviceWorker.register('/notification-sw.js')
        console.log('Service Worker registered:', registration)
      } catch (error) {
        console.error('Service Worker registration failed:', error)
      }
    }
  }

  const showNotification = (title: string, body: string, icon: string = '/icon.png') => {
    if (typeof window !== 'undefined' && permissions.notification === 'granted' && 'Notification' in window) {
      new Notification(title, {
        body,
        icon,
        badge: '/badge.png',
        tag: 'autoreview-notification',
        requireInteraction: false,
        silent: false
      })
    }
  }

  // Simulate receiving a notification (for demo)
  const simulateNotification = () => {
    if (typeof window === 'undefined') return
    
    const notifications = [
      { title: '⭐ New 5-Star Review!', body: 'You received a new positive review on Google.' },
      { title: '🤖 AI Response Ready', body: 'Sarah has generated a response to your latest review.' },
      { title: '⚠️ Negative Review Alert', body: 'A customer left a 2-star review. Check it out!' },
      { title: '💳 Low Credits Warning', body: 'You have only 10 credits remaining.' }
    ]
    
    const random = notifications[Math.floor(Math.random() * notifications.length)]
    showNotification(random.title, random.body)
  }

  return (
    <>
      {/* Permission Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {/* Location Permission Card */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          className="glass-card border border-white/10 rounded-xl p-5"
        >
          <div className="flex items-start justify-between mb-4">
            <div className="flex items-center gap-3">
              <div className={`w-12 h-12 rounded-xl flex items-center justify-center ${
                permissions.location === 'granted' 
                  ? 'bg-emerald-500/20' 
                  : permissions.location === 'denied'
                  ? 'bg-red-500/20'
                  : 'bg-amber-500/20'
              }`}>
                <MapPin className={`w-6 h-6 ${
                  permissions.location === 'granted' 
                    ? 'text-emerald-400' 
                    : permissions.location === 'denied'
                    ? 'text-red-400'
                    : 'text-amber-400'
                }`} />
              </div>
              <div>
                <h3 className="text-white font-semibold">Location Access</h3>
                <p className="text-white/50 text-sm">
                  {permissions.location === 'granted' 
                    ? 'Access granted' 
                    : permissions.location === 'denied'
                    ? 'Access denied'
                    : 'Permission needed'}
                </p>
              </div>
            </div>
            {permissions.location === 'granted' && (
              <CheckCircle className="w-5 h-5 text-emerald-400" />
            )}
            {permissions.location === 'denied' && (
              <XCircle className="w-5 h-5 text-red-400" />
            )}
          </div>

          {userLocation && (
            <div className="mb-4 p-3 bg-emerald-500/10 border border-emerald-500/20 rounded-lg">
              <div className="flex items-center gap-2 text-emerald-400 text-sm mb-1">
                <Navigation className="w-4 h-4" />
                <span className="font-medium">Current Location</span>
              </div>
              <p className="text-white/80 text-sm">
                {userLocation.city && userLocation.country 
                  ? `${userLocation.city}, ${userLocation.country}`
                  : `${userLocation.latitude.toFixed(4)}, ${userLocation.longitude.toFixed(4)}`}
              </p>
            </div>
          )}

          <button
            onClick={() => {
              if (permissions.location === 'granted') {
                setShowLocationModal(true)
              } else {
                requestLocation()
              }
            }}
            disabled={isRequesting || permissions.location === 'denied'}
            className={`w-full py-2.5 rounded-lg font-medium transition-all flex items-center justify-center gap-2 ${
              permissions.location === 'granted'
                ? 'bg-emerald-500/20 text-emerald-400 hover:bg-emerald-500/30'
                : permissions.location === 'denied'
                ? 'bg-gray-500/20 text-gray-400 cursor-not-allowed'
                : 'bg-primary text-primary-foreground hover:bg-primary/90'
            }`}
          >
            {isRequesting ? (
              <>
                <div className="w-4 h-4 border-2 border-current border-t-transparent rounded-full animate-spin" />
                Requesting...
              </>
            ) : permissions.location === 'granted' ? (
              <>
                <Settings className="w-4 h-4" />
                Manage Location
              </>
            ) : permissions.location === 'denied' ? (
              <>
                <Shield className="w-4 h-4" />
                Blocked in Browser
              </>
            ) : (
              <>
                <MapPin className="w-4 h-4" />
                Allow Location Access
              </>
            )}
          </button>
        </motion.div>

        {/* Notification Permission Card */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.1 }}
          className="glass-card border border-white/10 rounded-xl p-5"
        >
          <div className="flex items-start justify-between mb-4">
            <div className="flex items-center gap-3">
              <div className={`w-12 h-12 rounded-xl flex items-center justify-center ${
                permissions.notification === 'granted' 
                  ? 'bg-emerald-500/20' 
                  : permissions.notification === 'denied'
                  ? 'bg-red-500/20'
                  : 'bg-amber-500/20'
              }`}>
                {permissions.notification === 'granted' ? (
                  <BellRing className="w-6 h-6 text-emerald-400" />
                ) : permissions.notification === 'denied' ? (
                  <BellOff className="w-6 h-6 text-red-400" />
                ) : (
                  <Bell className="w-6 h-6 text-amber-400" />
                )}
              </div>
              <div>
                <h3 className="text-white font-semibold">Push Notifications</h3>
                <p className="text-white/50 text-sm">
                  {permissions.notification === 'granted' 
                    ? 'Notifications enabled' 
                    : permissions.notification === 'denied'
                    ? 'Notifications blocked'
                    : 'Enable for updates'}
                </p>
              </div>
            </div>
            {permissions.notification === 'granted' && (
              <CheckCircle className="w-5 h-5 text-emerald-400" />
            )}
            {permissions.notification === 'denied' && (
              <XCircle className="w-5 h-5 text-red-400" />
            )}
          </div>

          <div className="mb-4 space-y-2">
            <div className="flex items-center gap-2 text-white/70 text-sm">
              <CheckCircle className="w-4 h-4 text-emerald-400" />
              <span>New review alerts</span>
            </div>
            <div className="flex items-center gap-2 text-white/70 text-sm">
              <CheckCircle className="w-4 h-4 text-emerald-400" />
              <span>AI response ready</span>
            </div>
            <div className="flex items-center gap-2 text-white/70 text-sm">
              <CheckCircle className="w-4 h-4 text-emerald-400" />
              <span>Low credit warnings</span>
            </div>
          </div>

          <div className="flex gap-2">
            <button
              onClick={() => {
                if (permissions.notification === 'granted') {
                  simulateNotification()
                } else {
                  requestNotificationPermission()
                }
              }}
              disabled={isRequesting || permissions.notification === 'denied'}
              className={`flex-1 py-2.5 rounded-lg font-medium transition-all flex items-center justify-center gap-2 ${
                permissions.notification === 'granted'
                  ? 'bg-emerald-500/20 text-emerald-400 hover:bg-emerald-500/30'
                  : permissions.notification === 'denied'
                  ? 'bg-gray-500/20 text-gray-400 cursor-not-allowed'
                  : 'bg-primary text-primary-foreground hover:bg-primary/90'
              }`}
            >
              {isRequesting ? (
                <>
                  <div className="w-4 h-4 border-2 border-current border-t-transparent rounded-full animate-spin" />
                  Requesting...
                </>
              ) : permissions.notification === 'granted' ? (
                <>
                  <Bell className="w-4 h-4" />
                  Test Notification
                </>
              ) : permissions.notification === 'denied' ? (
                <>
                  <Shield className="w-4 h-4" />
                  Blocked in Browser
                </>
              ) : (
                <>
                  <BellRing className="w-4 h-4" />
                  Enable Notifications
                </>
              )}
            </button>
          </div>
        </motion.div>
      </div>

      {/* Location Details Modal */}
      <AnimatePresence>
        {showLocationModal && userLocation && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4"
            onClick={() => setShowLocationModal(false)}
          >
            <motion.div
              initial={{ scale: 0.9, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.9, opacity: 0 }}
              className="glass-card border border-white/10 rounded-2xl p-6 max-w-md w-full"
              onClick={e => e.stopPropagation()}
            >
              <div className="flex items-center gap-3 mb-6">
                <div className="w-12 h-12 bg-emerald-500/20 rounded-xl flex items-center justify-center">
                  <Navigation className="w-6 h-6 text-emerald-400" />
                </div>
                <div>
                  <h3 className="text-xl font-bold text-white">Your Location</h3>
                  <p className="text-white/60 text-sm">Detected from your device</p>
                </div>
              </div>

              <div className="space-y-4 mb-6">
                <div className="p-4 bg-white/5 rounded-xl">
                  <p className="text-white/50 text-xs mb-1">Coordinates</p>
                  <p className="text-white font-mono">
                    {userLocation.latitude.toFixed(6)}, {userLocation.longitude.toFixed(6)}
                  </p>
                </div>

                {userLocation.city && (
                  <div className="p-4 bg-white/5 rounded-xl">
                    <p className="text-white/50 text-xs mb-1">City</p>
                    <p className="text-white">{userLocation.city}</p>
                  </div>
                )}

                {userLocation.country && (
                  <div className="p-4 bg-white/5 rounded-xl">
                    <p className="text-white/50 text-xs mb-1">Country</p>
                    <p className="text-white">{userLocation.country}</p>
                  </div>
                )}

                {userLocation.address && (
                  <div className="p-4 bg-white/5 rounded-xl">
                    <p className="text-white/50 text-xs mb-1">Full Address</p>
                    <p className="text-white text-sm">{userLocation.address}</p>
                  </div>
                )}
              </div>

              <div className="flex gap-3">
                <button
                  onClick={() => requestLocation()}
                  className="flex-1 py-3 bg-primary text-primary-foreground rounded-xl font-medium hover:bg-primary/90 transition-colors"
                >
                  Update Location
                </button>
                <button
                  onClick={() => setShowLocationModal(false)}
                  className="flex-1 py-3 glass text-white rounded-xl font-medium hover:bg-white/10 transition-colors"
                >
                  Close
                </button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Info Banner */}
      <motion.div
        initial={{ opacity: 0, y: 10 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 0.2 }}
        className="mt-4 p-4 bg-blue-500/10 border border-blue-500/20 rounded-xl flex items-start gap-3"
      >
        <Info className="w-5 h-5 text-blue-400 shrink-0 mt-0.5" />
        <div>
          <p className="text-white/80 text-sm">
            <span className="font-semibold text-white">Why do we need these permissions?</span>
          </p>
          <ul className="text-white/60 text-sm mt-2 space-y-1">
            <li>• <strong>Location:</strong> To show local business insights and nearby reviews</li>
            <li>• <strong>Notifications:</strong> To alert you about new reviews and AI responses in real-time</li>
          </ul>
          <p className="text-white/40 text-xs mt-2">
            Your data is secure and never shared with third parties. You can revoke permissions anytime.
          </p>
        </div>
      </motion.div>
    </>
  )
}

// Utility function to show notification from anywhere in the app
export const showBrowserNotification = (title: string, body: string, icon: string = '/icon.png') => {
  if (typeof window !== 'undefined' && 'Notification' in window && Notification.permission === 'granted') {
    new Notification(title, {
      body,
      icon,
      badge: '/badge.png',
      tag: 'autoreview-notification',
      requireInteraction: false
    })
  }
}

// Utility to check if notifications are enabled
export const areNotificationsEnabled = (): boolean => {
  return typeof window !== 'undefined' && 'Notification' in window && Notification.permission === 'granted'
}

// Utility to get user location
export const getUserLocation = (): UserLocation | null => {
  const saved = localStorage.getItem('user-location')
  return saved ? JSON.parse(saved) : null
}

'use client'

import { motion } from 'framer-motion'
import { Star, Sparkles, MessageSquare, ExternalLink, Calendar } from 'lucide-react'
import { useRouter } from 'next/navigation'

interface Review {
  id: string
  reviewer_name?: string
  author_name?: string
  rating: number
  review_text?: string
  content?: string
  platform: string
  sentiment_label: 'positive' | 'negative' | 'neutral' | null
  status: 'pending' | 'approved' | 'rejected'
  created_at: string
  reply?: {
    id: string
    reply_text?: string
    content?: string
    ai_generated?: boolean
  } | null
}

interface ReviewItemProps {
  review: Review
  index?: number
}

const platformIcons: Record<string, string> = {
  google: '🔍',
  facebook: '📘',
  yelp: '⭐',
  tripadvisor: '✈️',
  trustpilot: '💚',
  manual: '📝',
}

const sentimentConfig = {
  positive: { color: 'bg-emerald-500/20 text-emerald-400 border-emerald-500/30', label: 'Positive' },
  negative: { color: 'bg-rose-500/20 text-rose-400 border-rose-500/30', label: 'Negative' },
  neutral: { color: 'bg-amber-500/20 text-amber-400 border-amber-500/30', label: 'Neutral' },
}

const statusConfig = {
  pending: { color: 'bg-amber-500/10 text-amber-400', label: 'Pending' },
  approved: { color: 'bg-emerald-500/10 text-emerald-400', label: 'Replied' },
  rejected: { color: 'bg-rose-500/10 text-rose-400', label: 'Rejected' },
}

export default function ReviewItem({ review, index = 0 }: ReviewItemProps) {
  const router = useRouter()
  const authorName = review.reviewer_name || review.author_name || 'Anonymous'
  const reviewText = review.review_text || review.content || ''
  const replyText = review.reply?.reply_text || review.reply?.content || ''
  const platformIcon = platformIcons[review.platform] || '🌐'

  const sentiment = review.sentiment_label ? sentimentConfig[review.sentiment_label] : null
  const status = statusConfig[review.status]

  return (
    <motion.div
      initial={{ opacity: 0, x: -20 }}
      animate={{ opacity: 1, x: 0 }}
      transition={{ duration: 0.4, delay: index * 0.1 }}
      className="group relative overflow-hidden rounded-xl border border-gray-800 bg-gradient-to-br from-gray-900/80 to-gray-900/40 p-4 sm:p-5 transition-all duration-300 hover:border-gray-700 hover:shadow-lg touch-enhanced"
    >
      {/* Left accent line */}
      <div className={`absolute left-0 top-0 h-full w-1 transition-all duration-300 ${
        review.status === 'approved' ? 'bg-emerald-500' :
        review.status === 'rejected' ? 'bg-rose-500' : 'bg-amber-500'
      }`} />

      <div className="pl-3 sm:pl-4">
        {/* Header - Stacked layout on mobile */}
        <div className="flex flex-col sm:flex-row sm:flex-wrap items-start sm:items-center justify-between gap-3">
          <div className="flex items-center gap-3 w-full sm:w-auto">
            {/* Avatar */}
            <div className="flex h-10 w-10 sm:h-12 sm:w-12 items-center justify-center rounded-full bg-gradient-to-br from-purple-500 to-pink-500 text-sm sm:text-base font-bold text-white">
              {authorName.charAt(0).toUpperCase()}
            </div>

            <div className="flex-1 min-w-0">
              <div className="flex flex-wrap items-center gap-2">
                <h4 className="font-semibold text-white text-sm sm:text-base truncate">{authorName}</h4>
                <span className="text-lg sm:text-xl" title={review.platform}>{platformIcon}</span>
              </div>
              <div className="flex items-center gap-1.5 sm:gap-2 text-xs text-gray-500 mt-1">
                <Calendar className="h-3 w-3 sm:h-3.5 sm:w-3.5" />
                <span className="truncate">
                  {new Date(review.created_at).toLocaleDateString('en-US', {
                    month: 'short',
                    day: 'numeric',
                    year: 'numeric'
                  })}
                </span>
              </div>
            </div>
          </div>

          {/* Rating and badges - Stacked on mobile */}
          <div className="flex flex-wrap items-center gap-2 sm:gap-3">
            <div className="flex items-center gap-1">
              {[...Array(5)].map((_, i) => (
                <Star
                  key={i}
                  className={`h-3.5 w-3.5 sm:h-4 sm:w-4 ${i < review.rating ? 'fill-yellow-500 text-yellow-500' : 'text-gray-700'}`}
                />
              ))}
            </div>
            <div className="flex flex-wrap items-center gap-1 sm:gap-2">
              {sentiment && (
                <span className={`rounded-full border px-2 py-0.5 sm:px-2.5 sm:py-1 text-[10px] sm:text-xs font-medium ${sentiment.color}`}>
                  {sentiment.label}
                </span>
              )}
              <span className={`rounded-full px-2 py-0.5 sm:px-2.5 sm:py-1 text-[10px] sm:text-xs font-medium ${status.color}`}>
                {status.label}
              </span>
            </div>
          </div>
        </div>

        {/* Review Content */}
        <p className="mt-3 text-sm sm:text-base leading-relaxed text-gray-300 line-clamp-2 sm:line-clamp-3">
          {reviewText}
        </p>

        {/* AI Reply Preview */}
        {replyText && (
          <div className="mt-3 rounded-lg border border-purple-500/20 bg-purple-500/10 p-3">
            <div className="flex flex-wrap items-center gap-2">
              <Sparkles className="h-3.5 w-3.5 text-purple-400" />
              <span className="text-xs font-medium text-purple-400">AI Reply</span>
              {review.reply?.ai_generated && (
                <span className="rounded-full bg-purple-500/20 px-2 py-0.5 text-[10px] text-purple-300">
                  AI Generated
                </span>
              )}
            </div>
            <p className="mt-1 text-xs text-gray-400 line-clamp-2">{replyText}</p>
          </div>
        )}

        {/* Actions - Stacked on mobile */}
        <div className="mt-4 flex flex-col sm:flex-row items-start sm:items-center justify-between gap-3">
          <div className="flex flex-wrap items-center gap-2">
            {review.status === 'pending' && !replyText && (
              <button className="flex items-center gap-1.5 rounded-lg bg-purple-500/20 px-3 py-2 text-xs sm:text-sm font-medium text-purple-400 transition-colors hover:bg-purple-500/30 touch-target">
                <Sparkles className="h-3.5 w-3.5" />
                Generate Reply
              </button>
            )}
          </div>

          <button
            onClick={() => router.push(`/reviews?id=${review.id}`)}
            className="flex items-center gap-1 text-xs sm:text-sm text-gray-500 transition-colors hover:text-white touch-target px-3 py-2 rounded-lg hover:bg-white/5"
          >
            View Details
            <ExternalLink className="h-3 w-3 sm:h-3.5 sm:w-3.5" />
          </button>
        </div>
      </div>
    </motion.div>
  )
}

'use client'

import { useState, useEffect, useCallback } from 'react'

interface LocationState {
  latitude: number | null
  longitude: number | null
  accuracy: number | null
  altitude: number | null
  heading: number | null
  speed: number | null
  timestamp: number | null
}

interface AddressInfo {
  city: string | null
  country: string | null
  region: string | null
  postalCode: string | null
  street: string | null
  fullAddress: string | null
}

interface UseLocationReturn {
  // Location data
  location: LocationState
  address: AddressInfo | null
  
  // Permission state
  permission: 'granted' | 'denied' | 'prompt' | 'checking'
  supported: boolean
  
  // Loading states
  loading: boolean
  error: string | null
  
  // Actions
  requestLocation: () => Promise<boolean>
  refreshLocation: () => Promise<boolean>
  clearLocation: () => void
  
  // Utilities
  getDistanceFrom: (lat: number, lon: number) => number | null
  isNearLocation: (lat: number, lon: number, radiusKm: number) => boolean
}

export function useLocation(): UseLocationReturn {
  const [location, setLocation] = useState<LocationState>({
    latitude: null,
    longitude: null,
    accuracy: null,
    altitude: null,
    heading: null,
    speed: null,
    timestamp: null
  })
  
  const [address, setAddress] = useState<AddressInfo | null>(null)
  const [permission, setPermission] = useState<'granted' | 'denied' | 'prompt' | 'checking'>('checking')
  const [supported, setSupported] = useState(false)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)

  // Check support and load saved location
  useEffect(() => {
    const checkSupport = () => {
      const isSupported = 'geolocation' in navigator
      setSupported(isSupported)
      
      // Don't show error automatically - only show when user tries to request
      if (!isSupported) {
        setPermission('denied')
      }
    }

    checkSupport()
    loadSavedLocation()
    checkPermission()
  }, [])

  // Check current permission status
  const checkPermission = async () => {
    if (!('geolocation' in navigator)) return

    try {
      if ('permissions' in navigator) {
        const result = await navigator.permissions.query({ name: 'geolocation' as PermissionName })
        setPermission(result.state as 'granted' | 'denied' | 'prompt')
        
        result.addEventListener('change', () => {
          setPermission(result.state as 'granted' | 'denied' | 'prompt')
        })
      }
    } catch (err) {
      // Silently handle permission check error
    }
  }

  // Load saved location from localStorage
  const loadSavedLocation = () => {
    try {
      const saved = localStorage.getItem('user-location')
      if (saved) {
        const parsed = JSON.parse(saved)
        setLocation({
          latitude: parsed.latitude || null,
          longitude: parsed.longitude || null,
          accuracy: parsed.accuracy || null,
          altitude: parsed.altitude || null,
          heading: parsed.heading || null,
          speed: parsed.speed || null,
          timestamp: parsed.timestamp || null
        })
        
        if (parsed.city || parsed.country) {
          setAddress({
            city: parsed.city || null,
            country: parsed.country || null,
            region: parsed.region || null,
            postalCode: parsed.postalCode || null,
            street: parsed.street || null,
            fullAddress: parsed.address || null
          })
        }
      }
    } catch (err) {
      // Silently handle localStorage error
    }
  }

  // Save location to localStorage
  const saveLocation = (loc: LocationState, addr?: AddressInfo) => {
    try {
      const data = {
        ...loc,
        city: addr?.city,
        country: addr?.country,
        region: addr?.region,
        postalCode: addr?.postalCode,
        street: addr?.street,
        address: addr?.fullAddress,
        savedAt: new Date().toISOString()
      }
      localStorage.setItem('user-location', JSON.stringify(data))
    } catch (err) {
      // Silently handle localStorage save error
    }
  }

  // Reverse geocode coordinates to address
  const reverseGeocode = async (lat: number, lon: number): Promise<AddressInfo | null> => {
    try {
      // Using OpenStreetMap Nominatim (free, no API key required)
      const response = await fetch(
        `https://nominatim.openstreetmap.org/reverse?format=json&lat=${lat}&lon=${lon}&zoom=18&addressdetails=1`,
        { 
          headers: { 
            'Accept-Language': 'en-US,en',
            'User-Agent': 'AutoReviewAI/1.0'
          } 
        }
      )
      
      if (!response.ok) throw new Error('Geocoding failed')
      
      const data = await response.json()
      
      return {
        city: data.address?.city || data.address?.town || data.address?.village || null,
        country: data.address?.country || null,
        region: data.address?.state || data.address?.region || null,
        postalCode: data.address?.postcode || null,
        street: data.address?.road || data.address?.street || null,
        fullAddress: data.display_name || null
      }
    } catch (err) {
      // Silently handle error - Chrome extensions often interfere with fetch
      return null
    }
  }

  // Request current location
  const requestLocation = useCallback(async (): Promise<boolean> => {
    if (!supported) {
      setError('Geolocation is not supported by your browser')
      return false
    }

    // Check if running on HTTPS or localhost
    if (typeof window !== 'undefined' && window.location.protocol !== 'https:' && window.location.hostname !== 'localhost') {
      setError('Location access requires HTTPS connection')
      return false
    }

    setLoading(true)
    setError(null)

    return new Promise((resolve) => {
      navigator.geolocation.getCurrentPosition(
        async (position) => {
          const newLocation: LocationState = {
            latitude: position.coords.latitude,
            longitude: position.coords.longitude,
            accuracy: position.coords.accuracy,
            altitude: position.coords.altitude,
            heading: position.coords.heading,
            speed: position.coords.speed,
            timestamp: position.timestamp
          }
          
          setLocation(newLocation)
          setPermission('granted')
          
          // Get address from coordinates
          const addr = await reverseGeocode(
            position.coords.latitude,
            position.coords.longitude
          )
          
          if (addr) {
            setAddress(addr)
          }
          
          // Save to localStorage
          saveLocation(newLocation, addr || undefined)
          
          setLoading(false)
          resolve(true)
        },
        (err) => {
          // Silently handle geolocation errors (Chrome extensions often interfere)
          // No console logging to avoid spam
          
          let errorMessage = 'Unable to retrieve your location'
          let helpText = ''
          switch (err.code) {
            case err.PERMISSION_DENIED:
              errorMessage = 'Location access denied'
              helpText = 'Please enable location permissions in your browser settings'
              setPermission('denied')
              break
            case err.POSITION_UNAVAILABLE:
              errorMessage = 'Location information unavailable'
              helpText = 'Please check your device location settings'
              break
            case err.TIMEOUT:
              errorMessage = 'Location request timed out'
              helpText = 'Please try again or check your connection'
              break
          }
          
          setError(`${errorMessage}. ${helpText}`)
          setLoading(false)
          resolve(false)
        },
        {
          enableHighAccuracy: false, // Changed to false for better compatibility
          timeout: 15000, // Increased timeout
          maximumAge: 30000 // Allow cached location up to 30 seconds old
        }
      )
    })
  }, [supported])

  // Refresh location (same as request but with better semantics)
  const refreshLocation = useCallback(async (): Promise<boolean> => {
    return requestLocation()
  }, [requestLocation])

  // Clear saved location
  const clearLocation = useCallback(() => {
    localStorage.removeItem('user-location')
    setLocation({
      latitude: null,
      longitude: null,
      accuracy: null,
      altitude: null,
      heading: null,
      speed: null,
      timestamp: null
    })
    setAddress(null)
    setPermission('prompt')
  }, [])

  // Calculate distance from current location to given coordinates (Haversine formula)
  const getDistanceFrom = useCallback((lat: number, lon: number): number | null => {
    if (!location.latitude || !location.longitude) return null

    const R = 6371 // Earth's radius in kilometers
    const dLat = (lat - location.latitude) * (Math.PI / 180)
    const dLon = (lon - location.longitude) * (Math.PI / 180)
    
    const a = 
      Math.sin(dLat / 2) * Math.sin(dLat / 2) +
      Math.cos(location.latitude * (Math.PI / 180)) * 
      Math.cos(lat * (Math.PI / 180)) *
      Math.sin(dLon / 2) * Math.sin(dLon / 2)
    
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a))
    const distance = R * c
    
    return distance
  }, [location.latitude, location.longitude])

  // Check if given coordinates are within radius
  const isNearLocation = useCallback((lat: number, lon: number, radiusKm: number): boolean => {
    const distance = getDistanceFrom(lat, lon)
    if (distance === null) return false
    return distance <= radiusKm
  }, [getDistanceFrom])

  return {
    location,
    address,
    permission,
    supported,
    loading,
    error,
    requestLocation,
    refreshLocation,
    clearLocation,
    getDistanceFrom,
    isNearLocation
  }
}

export default useLocation

// Utility functions
export const formatCoordinates = (lat: number, lon: number, precision: number = 4): string => {
  return `${lat.toFixed(precision)}, ${lon.toFixed(precision)}`
}

export const formatAddress = (address: AddressInfo | null): string => {
  if (!address) return 'Unknown location'
  
  const parts = []
  if (address.city) parts.push(address.city)
  if (address.region) parts.push(address.region)
  if (address.country) parts.push(address.country)
  
  return parts.join(', ') || address.fullAddress || 'Unknown location'
}

export const getLocationAccuracyText = (accuracy: number | null): string => {
  if (!accuracy) return 'Unknown accuracy'
  if (accuracy < 10) return 'Very accurate'
  if (accuracy < 50) return 'Good accuracy'
  if (accuracy < 100) return 'Moderate accuracy'
  return 'Low accuracy'
}

'use client'

import { useState, useEffect, useCallback } from 'react'

interface NotificationState {
  permission: NotificationPermission | null
  supported: boolean
  serviceWorkerReady: boolean
}

interface NotificationAction {
  action: string
  title: string
  icon?: string
}

interface ShowNotificationOptions {
  title: string
  body: string
  icon?: string
  badge?: string
  tag?: string
  requireInteraction?: boolean
  silent?: boolean
  data?: Record<string, unknown>
}

export function useNotifications() {
  const [state, setState] = useState<NotificationState>({
    permission: null,
    supported: false,
    serviceWorkerReady: false
  })

  // Check if notifications are supported and get current permission
  useEffect(() => {
    const checkSupport = () => {
      const supported = 'Notification' in window
      const permission = supported ? Notification.permission : null
      
      setState(prev => ({
        ...prev,
        supported,
        permission
      }))
    }

    checkSupport()
  }, [])

  // Check service worker registration
  useEffect(() => {
    const checkServiceWorker = async () => {
      if ('serviceWorker' in navigator) {
        try {
          const registration = await navigator.serviceWorker.ready
          setState(prev => ({
            ...prev,
            serviceWorkerReady: !!registration
          }))
        } catch (error) {
          console.error('Service Worker not ready:', error)
        }
      }
    }

    checkServiceWorker()
  }, [])

  // Request notification permission
  const requestPermission = useCallback(async (): Promise<boolean> => {
    if (!state.supported) {
      console.warn('Notifications not supported')
      return false
    }

    try {
      const permission = await Notification.requestPermission()
      setState(prev => ({ ...prev, permission }))
      
      if (permission === 'granted') {
        // Register service worker if not already done
        await registerServiceWorker()
      }
      
      return permission === 'granted'
    } catch (error) {
      console.error('Error requesting notification permission:', error)
      return false
    }
  }, [state.supported])

  // Register service worker
  const registerServiceWorker = async (): Promise<ServiceWorkerRegistration | null> => {
    if (!('serviceWorker' in navigator)) {
      return null
    }

    try {
      const registration = await navigator.serviceWorker.register('/notification-sw.js')
      console.log('Service Worker registered:', registration)
      setState(prev => ({ ...prev, serviceWorkerReady: true }))
      return registration
    } catch (error) {
      console.error('Service Worker registration failed:', error)
      return null
    }
  }

  // Show notification
  const showNotification = useCallback((options: ShowNotificationOptions): boolean => {
    // Check if notifications are supported and permission is granted
    if (!state.supported) {
      console.warn('Cannot show notification: notifications not supported')
      return false
    }

    if (state.permission !== 'granted') {
      console.warn('Cannot show notification: permission not granted')
      return false
    }

    try {
      const notificationOptions: NotificationOptions = {
        body: options.body,
        icon: options.icon || '/icon.png',
        badge: options.badge || '/badge.png',
        tag: options.tag || 'autoreview-notification',
        requireInteraction: options.requireInteraction || false,
        silent: options.silent || false,
        data: options.data || { url: '/dashboard' }
      }

      const notification = new Notification(options.title, notificationOptions)

      // Handle notification click
      notification.onclick = () => {
        window.focus()
        notification.close()

        // Navigate to the specified URL
        const url = typeof options.data?.url === 'string' ? options.data.url : '/dashboard'
        window.location.href = url
      }

      return true
    } catch (error) {
      console.error('Error showing notification:', error)
      return false
    }
  }, [state.supported, state.permission])

  // Show notification via service worker (for background notifications)
  const showNotificationViaSW = useCallback(async (options: ShowNotificationOptions): Promise<boolean> => {
    if (!state.serviceWorkerReady) {
      // Fallback to regular notification
      return showNotification(options)
    }

    try {
      const registration = await navigator.serviceWorker.ready
      
      // Create notification options with extended type support
      const notificationOptions: NotificationOptions & { actions?: NotificationAction[] } = {
        body: options.body,
        icon: options.icon || '/icon.png',
        badge: options.badge || '/badge.png',
        tag: options.tag || 'autoreview-notification',
        requireInteraction: options.requireInteraction || false,
        silent: options.silent || false,
        data: options.data || { url: '/dashboard' },
        actions: [
          { action: 'open', title: 'Open App' },
          { action: 'dismiss', title: 'Dismiss' }
        ] as NotificationAction[]
      }
      
      await registration.showNotification(options.title, notificationOptions)

      return true
    } catch (error) {
      console.error('Error showing notification via SW:', error)
      // Fallback to regular notification
      return showNotification(options)
    }
  }, [state.serviceWorkerReady, showNotification])

  // Send message to service worker
  const sendMessageToSW = useCallback(async (message: Record<string, unknown>): Promise<unknown> => {
    if (!state.serviceWorkerReady) {
      console.warn('Service Worker not ready')
      return null
    }

    try {
      const registration = await navigator.serviceWorker.ready
      
      return new Promise((resolve) => {
        const messageChannel = new MessageChannel()
        
        messageChannel.port1.onmessage = (event) => {
          resolve(event.data)
        }
        
        registration.active?.postMessage(message, [messageChannel.port2])
      })
    } catch (error) {
      console.error('Error sending message to SW:', error)
      return null
    }
  }, [state.serviceWorkerReady])

  // Schedule a notification (for reminders)
  const scheduleNotification = useCallback((delayMs: number, options: ShowNotificationOptions): number => {
    const timeoutId = window.setTimeout(() => {
      showNotification(options)
    }, delayMs)

    return timeoutId
  }, [showNotification])

  // Cancel scheduled notification
  const cancelScheduledNotification = useCallback((timeoutId: number) => {
    window.clearTimeout(timeoutId)
  }, [])

  return {
    // State
    supported: state.supported,
    permission: state.permission,
    serviceWorkerReady: state.serviceWorkerReady,
    isGranted: state.permission === 'granted',
    isDenied: state.permission === 'denied',
    isPrompt: state.permission === 'default' || state.permission === null,
    
    // Actions
    requestPermission,
    showNotification,
    showNotificationViaSW,
    registerServiceWorker,
    sendMessageToSW,
    scheduleNotification,
    cancelScheduledNotification
  }
}

export default useNotifications

// Utility function to create common notification types
export const createReviewNotification = (
  platform: string,
  rating: number,
  reviewerName?: string
): ShowNotificationOptions => {
  const isPositive = rating >= 4
