      ? `⭐ New ${rating}-Star Review!` 
      : isNegative 
        ? `⚠️ New ${rating}-Star Review` 
        : `New ${rating}-Star Review`,
    body: reviewerName 
      ? `${reviewerName} left a review on ${platform}`
      : `You received a new review on ${platform}`,
