// Platform Integration Manager
export class PlatformIntegrationManager {
  private static STORAGE_KEY = 'autoreview-platforms-v2'

  // Get user's current plan
  private static getUserPlan(): string {
    if (typeof window === 'undefined') return 'free'
    
    // Get from localStorage
    const savedPlan = localStorage.getItem('autoreview-plan')
    return savedPlan || 'free'
  }

  // Get max platforms allowed for current plan
  private static getMaxPlatforms(): number {
    const plan = this.getUserPlan()
    const limits: Record<string, number> = {
      'free': 2,
      'starter': 5,
      'professional': 100, // Unlimited
      'enterprise': 100 // Unlimited
    }
    return limits[plan] || 2
  }

  // Check if user can connect more platforms
  static canConnectMore(): boolean {
    if (typeof window === 'undefined') return false
    
    const platforms = this.getPlatforms()
    const connected = platforms.filter(p => p.connected).length
    const max = this.getMaxPlatforms()
    
    return connected < max
  }

  // Get connection limit message
  static getConnectionLimitMessage(): string {
    const plan = this.getUserPlan()
    const limits: Record<string, string> = {
      'free': 'Free plan: Max 2 platforms. Upgrade for more!',
      'starter': 'Starter plan: Max 5 platforms. Upgrade for unlimited!',
      'professional': 'Connected platforms: Unlimited',
      'enterprise': 'Connected platforms: Unlimited'
    }
    return limits[plan] || limits['free']
  }

  // Validate credentials before saving
  static validateCredentials(platformId: string, credentials: Record<string, string>): string | null {
    // Check for empty credentials object
    if (!credentials || Object.keys(credentials).length === 0) {
      return 'No credentials provided'
    }

    // Platform-specific validation
    switch (platformId) {
      case 'google':
        if (!credentials.access_token?.trim()) {
          return 'Google access_token is required'
        }
        if (credentials.access_token.length < 10) {
          return 'Google access_token appears to be invalid (too short)'
        }
        // Google refresh token can be empty for some flows, but warn if completely missing
        if (!credentials.refresh_token?.trim()) {
          console.warn('[Platform Integration] Google refresh_token is empty. Token refresh will fail after 24 hours.')
        }
        break

      case 'facebook':
        if (!credentials.access_token?.trim()) {
          return 'Facebook access_token is required'
        }
        if (credentials.access_token.length < 20) {
          return 'Facebook access_token appears to be invalid (too short)'
        }
        break

      case 'yelp':
        if (!credentials.access_token?.trim()) {
          return 'Yelp access_token is required'
        }
        if (credentials.access_token.length < 20) {
          return 'Yelp access_token appears to be invalid (too short)'
        }
        break

      case 'trustpilot':
        if (!credentials.api_key?.trim()) {
          return 'Trustpilot API key is required'
        }
        if (credentials.api_key.length < 10) {
          return 'Trustpilot API key appears to be invalid (too short)'
        }
        break

      default:
        // Generic validation for unknown platforms
        const hasAnyCredential = Object.values(credentials).some(v => v?.trim())
        if (!hasAnyCredential) {
          return 'At least one credential field is required'
        }
    }

    // Check for obviously invalid patterns
    for (const [key, value] of Object.entries(credentials)) {
      if (typeof value === 'string') {
        if (value.includes('\n') || value.includes('\r')) {
          return `Credential "${key}" contains invalid line breaks`
        }
        if (value.includes(' ') && key.includes('token')) {
          return `Credential "${key}" (token) should not contain spaces`
        }
      }
    }

    return null // All validations passed
  }

  // Get all platforms with their current status
  static getPlatforms(): PlatformConfig[] {
    if (typeof window === 'undefined') return []
    
    try {
      const stored = localStorage.getItem(this.STORAGE_KEY)
      if (stored) {
        const parsed = JSON.parse(stored)
        // Decrypt credentials
        return parsed.map((p: PlatformConfig) => ({
          ...p,
          credentials: Object.fromEntries(
            Object.entries(p.credentials).map(([k, v]) => [k, decryptData(v as string)])
          )
        }))
      }
    } catch (error) {
      console.error('Error loading platforms:', error)
    }

    // Return default platforms
    return Object.entries(platformDefinitions).map(([id, def]) => ({
      id,
      name: def.name,
      icon: def.icon,
      description: def.description,
      connected: false,
      credentials: {},
      status: 'disconnected'
    }))
  }

  // Save platform configuration
  static savePlatform(platformId: string, credentials: Record<string, string>): { success: boolean; error?: string } {
    if (typeof window === 'undefined') return { success: false, error: 'localStorage not available on server' }
    
    try {
      // Validate credentials before saving
      const validationError = this.validateCredentials(platformId, credentials)
      if (validationError) {
        console.warn(`[Platform Integration] Validation failed for ${platformId}:`, validationError)
        return { success: false, error: validationError }
      }

      const platforms = this.getPlatforms()
      const index = platforms.findIndex(p => p.id === platformId)
      
      if (index !== -1) {
        // Encrypt credentials before storing
        const encryptedCredentials = Object.fromEntries(
          Object.entries(credentials).map(([k, v]) => [k, encryptData(v)])
        )
        
        platforms[index] = {
          ...platforms[index],
          credentials: encryptedCredentials,
          connected: true,
          status: 'connected',
          lastSync: new Date().toISOString()
        }
        
        localStorage.setItem(this.STORAGE_KEY, JSON.stringify(platforms))
        return { success: true }
      } else {
        return { success: false, error: 'Platform not found' }
      }
    } catch (error) {
      console.error('Error saving platform:', error)
      return { success: false, error: error instanceof Error ? error.message : 'Unknown error' }
    }
  }

  // Update platform status
  static updatePlatformStatus(platformId: string, status: PlatformConfig['status'], errorMessage?: string): void {
    if (typeof window === 'undefined') return
    
    try {
      const platforms = this.getPlatforms()
      const index = platforms.findIndex(p => p.id === platformId)
      
      if (index !== -1) {
        platforms[index] = {
          ...platforms[index],
          status,
          errorMessage,
          lastSync: status === 'connected' ? new Date().toISOString() : platforms[index].lastSync
        }
        
        // Re-encrypt before saving
        const encryptedPlatforms = platforms.map(p => ({
          ...p,
          credentials: Object.fromEntries(
            Object.entries(p.credentials).map(([k, v]) => [k, encryptData(v)])
          )
        }))
        
        localStorage.setItem(this.STORAGE_KEY, JSON.stringify(encryptedPlatforms))
      }
    } catch (error) {
      console.error('Error updating platform status:', error)
    }
  }

  // Disconnect a platform
  static disconnectPlatform(platformId: string): boolean {
    if (typeof window === 'undefined') return false
    
    try {
      const platforms = this.getPlatforms()
      const index = platforms.findIndex(p => p.id === platformId)
      
      if (index !== -1) {
        platforms[index] = {
          ...platforms[index],
          connected: false,
          credentials: {},
          status: 'disconnected',
          errorMessage: undefined
        }
        
        localStorage.setItem(this.STORAGE_KEY, JSON.stringify(platforms))
        return true
      }
    } catch (error) {
      console.error('Error disconnecting platform:', error)
    }
    return false
  }

  // Test connection (real API implementation)
  static async testConnection(platformId: string, credentials: Record<string, string>): Promise<{ success: boolean; message: string }> {
    if (typeof window === 'undefined') {
      return { success: false, message: 'Loading...' }
    }

    const requiredFields = platformDefinitions[platformId]?.fields || []
    
    for (const field of requiredFields) {
      if (field.required && !credentials[field.name]) {
        return {
          success: false,
          message: `Missing required field: ${field.label}`
        }
      }
    }

    // Google
    if (platformId === 'google') {
      try {
        const res = await fetch(
          `https://maps.googleapis.com/maps/api/place/details/json?place_id=${credentials.placeId}&fields=name&key=${credentials.apiKey}`
        )
        if (!res.ok) {
          return { success: false, message: `Google API error: ${res.status}` }
        }
        const data = await res.json()
        if (data.status === 'OK') return { success: true, message: 'Google connected!' }
        return { success: false, message: `Google Error: ${data.status}` }
      } catch (err) {
        return { success: false, message: 'Failed to connect to Google. Check your internet connection.' }
      }
    }

    // Yelp
    if (platformId === 'yelp') {
      try {
        const res = await fetch(
          `https://api.yelp.com/v3/businesses/${credentials.businessId}`,
          { headers: { Authorization: `Bearer ${credentials.apiKey}` } }
        )
        if (!res.ok) {
          return { success: false, message: 'Invalid Yelp credentials or API key' }
        }
        return { success: true, message: 'Yelp connected!' }
      } catch (err) {
        return { success: false, message: 'Failed to connect to Yelp. Check your internet connection.' }
      }
    }

    // Facebook
    if (platformId === 'facebook') {
      try {
        const res = await fetch(
          `https://graph.facebook.com/${credentials.pageId}?access_token=${credentials.pageAccessToken}`
        )
        if (!res.ok) {
          return { success: false, message: 'Invalid Facebook token or page ID' }
        }
        const data = await res.json()
        if (data.id) return { success: true, message: 'Facebook connected!' }
        return { success: false, message: 'Invalid Facebook credentials' }
      } catch (err) {
        return { success: false, message: 'Failed to connect to Facebook. Check your internet connection.' }
      }
    }

    // TripAdvisor
    if (platformId === 'tripadvisor') {
      try {
        const res = await fetch(
          `https://api.content.tripadvisor.com/api/v1/location/${credentials.locationId}/details?key=${credentials.apiKey}`
        )
        if (!res.ok) {
          return { success: false, message: 'Invalid TripAdvisor key or location ID' }
        }
        return { success: true, message: 'TripAdvisor connected!' }
      } catch (err) {
        return { success: false, message: 'Failed to connect to TripAdvisor. Check your internet connection.' }
      }
    }

    // Trustpilot
    if (platformId === 'trustpilot') {
      try {
        const res = await fetch(
          `https://api.trustpilot.com/v1/business-units/${credentials.businessUnitId}`,
          { headers: { Authorization: `Basic ${btoa(credentials.apiKey + ':')}` } }
        )
        if (!res.ok) {
          return { success: false, message: 'Invalid Trustpilot credentials' }
        }
        return { success: true, message: 'Trustpilot connected!' }
      } catch (err) {
        return { success: false, message: 'Failed to connect to Trustpilot. Check your internet connection.' }
      }
    }

    return { success: false, message: 'Unknown platform' }
  }

  // Fetch reviews from a platform
  static async fetchReviews(platformId: string): Promise<any[]> {
    const platform = this.getPlatforms().find(p => p.id === platformId)
    
    if (!platform || !platform.connected) {
      return []
    }

    const { credentials } = platform

    // Google Reviews
    if (platformId === 'google') {
      try {
        const res = await fetch(
          `https://maps.googleapis.com/maps/api/place/details/json?place_id=${credentials.placeId}&fields=reviews&key=${credentials.apiKey}`
        )
        const data = await res.json()
        if (data.result?.reviews) {
          return data.result.reviews.map((r: any) => ({
            id: r.author_name + '-' + r.time,
            content: r.text,
            rating: r.rating,
            author: r.author_name,
            date: new Date(r.time * 1000).toISOString(),
            platform: 'google'
          }))
        }
      } catch (e) {
        console.error('Error fetching Google reviews:', e)
      }
      return []
    }

    // Yelp Reviews
    if (platformId === 'yelp') {
      try {
        const res = await fetch(
          `https://api.yelp.com/v3/businesses/${credentials.businessId}/reviews`,
          { headers: { Authorization: `Bearer ${credentials.apiKey}` } }
        )
        const data = await res.json()
        if (data.reviews) {
          return data.reviews.map((r: any) => ({
            id: r.id,
            content: r.text,
            rating: r.rating,
            author: r.user.name,
            date: r.time_created,
            platform: 'yelp'
          }))
        }
      } catch (e) {
        console.error('Error fetching Yelp reviews:', e)
      }
      return []
    }

    // Facebook Reviews
    if (platformId === 'facebook') {
      try {
        const res = await fetch(
          `https://graph.facebook.com/${credentials.pageId}/ratings?access_token=${credentials.pageAccessToken}&fields=reviewer_name,rating,review_text,created_time`
        )
        const data = await res.json()
        if (data.data) {
          return data.data.map((r: any) => ({
            id: r.id,
            content: r.review_text,
            rating: r.rating,
            author: r.reviewer_name,
            date: r.created_time,
            platform: 'facebook'
          }))
        }
      } catch (e) {
        console.error('Error fetching Facebook reviews:', e)
      }
      return []
    }

    // TripAdvisor Reviews
    if (platformId === 'tripadvisor') {
      try {
        const res = await fetch(
          `https://api.content.tripadvisor.com/api/v1/location/${credentials.locationId}/reviews?key=${credentials.apiKey}`
        )
        const data = await res.json()
        if (data.data) {
          return data.data.map((r: any) => ({
            id: r.id,
            content: r.text,
            rating: r.rating,
            author: r.author,
            date: r.publish_date,
            platform: 'tripadvisor'
          }))
        }
      } catch (e) {
        console.error('Error fetching TripAdvisor reviews:', e)
      }
      return []
    }

    // Trustpilot Reviews
    if (platformId === 'trustpilot') {
      try {
        const res = await fetch(
          `https://api.trustpilot.com/v1/business-units/${credentials.businessUnitId}/reviews?apikey=${credentials.apiKey}`
        )
        const data = await res.json()
        if (data.reviews) {
          return data.reviews.map((r: any) => ({
            id: r.id,
            content: r.content,
            rating: r.stars,
            author: r.author.name,
            date: r.createdAt,
            platform: 'trustpilot'
          }))
        }
      } catch (e) {
        console.error('Error fetching Trustpilot reviews:', e)
      }
      return []
    }

    return []
  }

  // Get connected platforms count
  static getConnectedCount(): number {
    return this.getPlatforms().filter(p => p.connected).length
  }
}

/**
 * HYBRID WEBHOOK SYSTEM
 * Combines: API Webhooks + Manual Import + Screenshot Upload + Email Forwarding
 * 
 * This is the SOLUTION to API approval problems!
 * Users can choose their preferred method to get reviews into the system
 */

import { longcatAI } from '@/lib/longcatAI';

export type WebhookSource = 
  | 'google_api'      // Official Google API (requires approval)
  | 'facebook_api'    // Official Facebook API
  | 'yelp_api'        // Official Yelp API
  | 'manual_import'   // CSV/Excel upload
  | 'screenshot'      // Screenshot upload (OCR)
  | 'email_forward'   // Email forwarding
  | 'chrome_extension' // Chrome extension scraping
  | 'webhook_custom'; // Custom webhook URL

export interface IncomingReview {
  id: string;
  source: WebhookSource;
  platform: 'google' | 'facebook' | 'yelp' | 'tripadvisor' | 'trustpilot' | 'other';
  author: string;
  rating: number;
  text: string;
  date: string;
  raw_data?: any;
  media_url?: string; // For screenshots
  email_data?: any;   // For email forwarding
}

export interface ProcessedReview extends IncomingReview {
  sentiment: string;
  ai_reply?: string;
  confidence: number;
  needs_human_review: boolean;
  auto_approved: boolean;
  status: 'pending' | 'approved' | 'rejected' | 'posted';
  processed_at: string;
}

/**
 * Process incoming review from ANY source
 * This is the main entry point for the hybrid system
 */
export async function processIncomingReview(
  review: IncomingReview,
  options: {
    autoReply?: boolean;
    autoPost?: boolean;
    businessName?: string;
    businessType?: string;
    tone?: string;
    language?: string;
  } = {}
): Promise<ProcessedReview> {
  console.log(`[Hybrid Webhook] Processing review from ${review.source}`);

  // Step 1: Analyze sentiment
  const sentiment = await longcatAI.analyzeSentiment(review.text);

  // Step 2: Deep analysis
  const deepAnalysis = await longcatAI.deepAnalyzeReview(review.text);

  // Step 3: Generate AI reply
  let aiReply: string | undefined;
  if (options.autoReply !== false) {
    const tone = (options.tone as 'professional' | 'friendly' | 'apologetic' | 'enthusiastic') || (sentiment.sentiment === 'negative' ? 'apologetic' : 'friendly');
    const replyResult = await longcatAI.generateReviewResponse(
      review.text,
      review.rating,
      sentiment.sentiment,
      tone
    );
    aiReply = replyResult.response;
  }

  // Step 4: Determine auto-approval
  const autoApproved = shouldAutoApprove(review.rating, sentiment.sentiment, deepAnalysis.priority, sentiment.confidence);

  // Step 5: Determine final status
  let status: ProcessedReview['status'] = 'pending';
  if (autoApproved && options.autoPost) {
    status = 'posted';
  } else if (autoApproved) {
    status = 'approved';
  }

  const processed: ProcessedReview = {
    ...review,
    sentiment: sentiment.sentiment,
    ai_reply: aiReply,
    confidence: sentiment.confidence,
    needs_human_review: !autoApproved,
    auto_approved: autoApproved,
    status,
    processed_at: new Date().toISOString(),
  };

  console.log(`[Hybrid Webhook] Processed: ${sentiment.sentiment}, Auto-approved: ${autoApproved}`);

  return processed;
}

/**
 * Determine if review should be auto-approved
 */
function shouldAutoApprove(
  rating: number,
  sentiment: string,
  priority: string,
  confidence: number
): boolean {
  // Never auto-approve urgent/high priority
  if (priority === 'urgent' || priority === 'high') return false;

  // Auto-approve positive reviews with high confidence
  if (rating >= 4 && sentiment === 'positive' && confidence > 0.8) return true;

  // Auto-approve neutral with very high confidence
  if (sentiment === 'neutral' && confidence > 0.9) return true;

  // Everything else needs human review
  return false;
}

/**
 * MANUAL IMPORT: Process reviews from CSV/Excel
 */
export async function processManualImport(
  reviews: Array<{
    author?: string;
    rating: number;
    text: string;
    date?: string;
    platform?: string;
  }>,
  options?: any
): Promise<ProcessedReview[]> {
  console.log(`[Manual Import] Processing ${reviews.length} reviews`);

  const processed: ProcessedReview[] = [];

  for (const review of reviews) {
    const platform = (review.platform as 'google' | 'facebook' | 'yelp' | 'tripadvisor' | 'trustpilot' | 'other') || 'google';
    const incoming: IncomingReview = {
      id: `manual_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
      source: 'manual_import',
      platform: platform,
      author: review.author || 'Anonymous',
      rating: review.rating,
      text: review.text,
      date: review.date || new Date().toISOString(),
    };

    const result = await processIncomingReview(incoming, options);
    processed.push(result);
  }

  return processed;
}

/**
 * SCREENSHOT UPLOAD: Process review from screenshot
 * Uses OCR (simulated here, would use Tesseract or similar in production)
 */
export async function processScreenshot(
  imageBase64: string,
  metadata: {
    platform: string;
    extractedText?: string;
  },
  options?: any
): Promise<ProcessedReview> {
  console.log(`[Screenshot] Processing screenshot for ${metadata.platform}`);

  // In production, use OCR service like Tesseract.js or Google Vision API
  // For now, assume text is extracted or provided
  const extractedText = metadata.extractedText || await simulateOCR(imageBase64);

  // Parse the extracted text to find review details
  const parsed = parseReviewText(extractedText);

  const incoming: IncomingReview = {
    id: `screenshot_${Date.now()}`,
    source: 'screenshot',
    platform: metadata.platform as any,
    author: parsed.author || 'Anonymous',
    rating: parsed.rating || 5,
    text: parsed.text || extractedText,
    date: new Date().toISOString(),
    raw_data: { imageBase64: imageBase64.substring(0, 100) + '...' },
  };

  return processIncomingReview(incoming, options);
}

/**
 * EMAIL FORWARD: Process review from forwarded email
 */
export async function processEmailForward(
  emailData: {
    from: string;
    subject: string;
    body: string;
    platform_hint?: string;
  },
  options?: any
): Promise<ProcessedReview> {
  console.log(`[Email Forward] Processing email: ${emailData.subject}`);

  // Parse email to extract review
  const parsed = parseEmailContent(emailData);

  const platform = (emailData.platform_hint as 'google' | 'facebook' | 'yelp' | 'tripadvisor' | 'trustpilot' | 'other') || 'google';
  const incoming: IncomingReview = {
    id: `email_${Date.now()}`,
    source: 'email_forward',
    platform: platform,
    author: parsed.author || 'Customer',
    rating: parsed.rating || 5,
    text: parsed.text,
    date: new Date().toISOString(),
    email_data: emailData,
  };

  return processIncomingReview(incoming, options);
}

/**
 * CUSTOM WEBHOOK URL: Generate unique webhook URL for users
 */
export function generateWebhookUrl(userId: string): string {
  const webhookId = `${userId}_${generateSecureToken(16)}`;
  return `https://api.autoreview-ai.com/webhooks/reviews/${webhookId}`;
}

/**
 * Verify webhook signature (for security)
 */
export function verifyWebhookSignature(
  payload: string,
  signature: string,
  secret: string
): boolean {
  // In production, use crypto to verify HMAC signature
  // For now, simple check
  return signature.length > 0;
}

// Helper functions
function generateSecureToken(length: number): string {
  return Array.from(crypto.getRandomValues(new Uint8Array(length)))
    .map(b => b.toString(36).padStart(2, '0'))
    .join('')
    .substring(0, length);
}

